mapper.select:
SELECT d.id AS id, d.name AS name, d.category_id AS category_id, (SELECT name FROM category WHERE id = d.category_id) AS category_name, price, image, description, status, create_time, update_time, create_time, update_user FROM dish AS d
AND d.name LIKE '%${name}%'
AND d.category_id = #{categoryId}
AND status = #{status}
